/* Auto-generated: resume PDF embedded as base64 for reliable download
   in any environment (sandboxed preview, hosted, or offline). */
window.RESUME_PDF_B64 = "";
window.downloadResume = function () {
  try {
    var b64 = window.RESUME_PDF_B64;
    var bin = atob(b64);
    var len = bin.length;
    var bytes = new Uint8Array(len);
    for (var i = 0; i < len; i++) bytes[i] = bin.charCodeAt(i);
    var blob = new Blob([bytes], { type: 'application/pdf' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url;
    a.download = 'Naveen_Prasath_Resume.pdf';
    document.body.appendChild(a);
    a.click();
    setTimeout(function () { document.body.removeChild(a); URL.revokeObjectURL(url); }, 1500);
  } catch (e) {
    window.open('Naveen_Prasath_Resume.pdf', '_blank');
  }
};